using System;
using System.Threading;

class Program
{
    static void Main(string[] args)
    {
        Console.WriteLine("Əsas thread başladı.");

        // Yeni thread yaratmaq
        Thread workerThread = new Thread(DoWork);
        workerThread.Start();

        // Əsas thread-də iş
        for (int i = 1; i <= 3; i++)
        {
            Console.WriteLine($"Əsas thread: {i}");
            Thread.Sleep(500); // 0.5 saniyə gözləmə
        }

        Console.WriteLine("Əsas thread bitdi.");
    }

    static void DoWork()
    {
        for (int i = 1; i <= 3; i++)
        {
            Console.WriteLine($"İşçi thread: {i}");
            Thread.Sleep(700); // 0.7 saniyə gözləmə
        }
    }
}
// Output (mümkün ardıcıllıq):
// Əsas thread başladı.
// Əsas thread: 1
// İşçi thread: 1
// Əsas thread: 2
// İşçi thread: 2
// Əsas thread: 3
// Əsas thread bitdi.
// İşçi thread: 3

using System;
using System.Threading;

class Program
{
    static int counter = 0;
    static object lockObject = new object();

    static void Main(string[] args)
    {
        Console.WriteLine("Thread-lər başlayır...");

        Thread thread1 = new Thread(IncrementCounter);
        Thread thread2 = new Thread(IncrementCounter);

        thread1.Start();
        thread2.Start();

        thread1.Join(); // Thread 1-in bitməsini gözlə
        thread2.Join(); // Thread 2-nin bitməsini gözlə

        Console.WriteLine($"Nəticə: {counter}");
    }

    static void IncrementCounter()
    {
        for (int i = 0; i < 1000; i++)
        {
            lock (lockObject)
            {
                counter++;
            }
        }
    }
}
// Output:
// Thread-lər başlayır...
// Nəticə: 2000

